Amazon EMR runs managed Spark, Hive, and Presto clusters. Terraform provisions clusters that can be persistent (always-on) or transient (one job, then terminate).

```hcl
resource "aws_emr_cluster" "spark_batch" {
  name          = "spark-batch-prod"
  release_label = "emr-7.0.0"
  applications  = ["Spark", "Hadoop"]

  service_role = aws_iam_role.emr_service.arn

  ec2_attributes {
    instance_profile                  = aws_iam_instance_profile.emr_ec2.arn
    subnet_id                         = module.vpc.private_subnets[0]
    emr_managed_master_security_group = aws_security_group.emr_master.id
    emr_managed_slave_security_group  = aws_security_group.emr_worker.id
  }

  master_instance_group {
    instance_type = "m5.xlarge"
  }

  core_instance_group {
    instance_type  = "m5.2xlarge"
    instance_count = var.environment == "prod" ? 5 : 2
    # Use Spot for cost savings:
    bid_price = "0.40"
    ebs_config {
      size = 100
      type = "gp2"
    }
  }

  configurations_json = jsonencode([{
    Classification = "spark-defaults"
    Properties = {
      "spark.sql.adaptive.enabled" = "true"
      "spark.dynamicAllocation.enabled" = "true"
    }
  }])

  auto_termination_policy {
    idle_timeout = 3600  # terminate after 1h idle (cost control)
  }
}
```

De interview tip: Transient EMR (auto-terminate after job) is cheaper than persistent. Use Step Functions or Airflow to trigger transient clusters.
